const items = $input.all();
const resultados = [];

for (const item of items) {
  // 1. Buscar el texto dinámicamente dependiendo del tipo de evento de Slack
  let texto = "";
  if (item.json.text) {
    texto = item.json.text; // Ruta normal (mensaje nuevo)
  } else if (item.json.previous_message && item.json.previous_message.text) {
    texto = item.json.previous_message.text; // Ruta cuando el mensaje es borrado/editado
  } else if (item.json.message && item.json.message.text) {
    texto = item.json.message.text; // Otra variante de edición en Slack
  }

  // Si definitivamente no hay texto en ninguna ruta, saltamos este item
  if (!texto) continue;

  // 2. Extraer los datos usando Expresiones Regulares (Regex)
  const matchGuia = texto.match(/guía\s(\d+)/);
  const matchTelefono = texto.match(/TELÉFONO:\s*(\d+)/);
  const matchCiudad = texto.match(/CIUDAD:\s*(.+)/);

  // Extraemos todo el bloque de la novedad hasta donde dice *--DESTINO--*
  const matchNovedad = texto.match(/NOVEDAD:\s*([\s\S]*?)(?=\n\*--DESTINO--\*)/);

  // Verificamos que se hayan encontrado todos los campos
  if (matchGuia && matchTelefono && matchCiudad && matchNovedad) {
    const guia = matchGuia[1];
    const telefono = matchTelefono[1];
    const ciudad = matchCiudad[1].trim();
    const novedadCompleta = matchNovedad[1];

    // 3. Aplicar la condición
    const esNovedadOficina = novedadCompleta.includes("Tu pedido ha llegado a nuestra oficina") && 
                             novedadCompleta.includes("Está listo para ser reclamado");

    // Si cumple la condición, armamos el JSON de salida
    if (esNovedadOficina) {
      resultados.push({
        json: {
          "Numero de guia": guia,
          "CIUDAD": ciudad,
          "TELÉFONO": telefono
        }
      });
    }
  }
}

// Retornamos el array con los resultados.
return resultados;

const items = $input.all();

for (const item of items) {
  // 1. Tomamos los datos que SÍ llegaron a este nodo (los de la sucursal)
  const ciudad = item.json["CIUDAD"] || item.json["Municipio"]; 
  const oficina = item.json["Oficina"];

  // 2. "Rescatamos" los datos perdidos llamando directamente al nodo que los extrajo.
  // IMPORTANTE: Asegúrate de que 'Code in JavaScript' sea exactamente el nombre de ese nodo.
  const guia = $('Code in JavaScript').first().json["Numero de guia"];
  let telefono = $('Code in JavaScript').first().json["TELÉFONO"];

  // 3. Procesar el teléfono (validando que exista y limpiándolo)
  if (telefono) {
    telefono = telefono.toString().replace(/\D/g, ''); // Limpiar caracteres no numéricos

    if (telefono.length === 10) {
      telefono = '57' + telefono; // Indicativo Colombia
    }
  }

  // 4. Crear el mensaje con formato de WhatsApp (Sin emojis)
 const mensaje = `¡Hola! Te tenemos excelentes noticias.\n\nTu paquete con guía *${guia}* ya se encuentra en *${ciudad}* y está listo para ser reclamado.\n\n*Dirección de la oficina:* ${oficina}\n\nTe invitamos a recogerlo lo más pronto posible para evitar que sea devuelto.\n\nSi deseas consultar la ubicación exacta en el mapa, puedes ingresar a este enlace:\nhttps://www3.interrapidisimo.com/SitioOficinaMasCercana/\n\nPara más información sobre tu entrega, puedes contactar directamente a Interrapidisimo al *323 255 4455*.\n\n¡Gracias por tu tiempo!`;

  // 5. Codificar el texto para que los espacios funcionen en la URL
  const mensajeCodificado = encodeURIComponent(mensaje);

  // 6. Armar el enlace final de WhatsApp
  const enlaceWhatsApp = `https://wa.me/${telefono}?text=${mensajeCodificado}`;

  // 7. Guardamos el enlace y el mensaje en el JSON de salida
  item.json["Mensaje a Enviar"] = mensaje;
  item.json["Enlace WhatsApp"] = enlaceWhatsApp;
}

return items;

